<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#C792EA;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#BABED8;"> ourPlanetName </span><span style="--shiki-light:#D73A49;--shiki-dark:#89DDFF;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#89DDFF;"> &quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#C3E88D;">Earth</span><span style="--shiki-light:#032F62;--shiki-dark:#89DDFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#89DDFF;">;</span><span style="--shiki-light:#24292E;--shiki-dark:#BABED8;"> </span></span>
